        UnfreezeQueryRequestV1 request = new UnfreezeQueryRequestV1();
        request.setServiceUrl("http://apipcs4.dccnet.com.cn/api/jft/api/pay/unfreeze/query/V1");
        UnfreezeQueryRequestV1Biz bizContent = new UnfreezeQueryRequestV1Biz();
        bizContent.setAppId("10000000000000213532");//平台商户识别编号，平台商户在开放平台注册时在工行后台生成，可以通过api注册平台界面查看
        bizContent.setVendorId("12013");//平台商户为子商户通过我行商户API申请的编号
        bizContent.setOrderId("1543214821156");//平台对接方子订单ID，确保唯一
